OPTION_RE = re.compile(r"^([A-Z])\.\s*(.+)$")
ANSWER_RE = re.compile(r"^答案[：:]\s*(.+)$")
QUESTION_RE = re.compile(r"^(\d+)\.\s*(.+)$")


def extract_paragraphs_from_bytes(data: bytes) -> list[str]:
    with zipfile.ZipFile(io.BytesIO(data)) as zf:
        xml = zf.read("word/document.xml")
    root = ET.fromstring(xml)
    paragraphs = []
    for p in root.iter("{http://schemas.openxmlformats.org/wordprocessingml/2006/main}p"):
        texts = []
        for t in p.iter("{http://schemas.openxmlformats.org/wordprocessingml/2006/main}t"):
            if t.text:
                texts.append(t.text)
            if t.tail:
                texts.append(t.tail)
        line = "".join(texts).strip()
        if line:
            paragraphs.append(line)
    return paragraphs


def parse_single_choice(paras: list[str]) -> list[dict]:
    questions = []
    i = 0
    while i < len(paras):
        m = QUESTION_RE.match(paras[i])
        if m:
            stem = m.group(2)
            options = {}
            i += 1
            while i < len(paras):
                line = paras[i]
                am = ANSWER_RE.match(line)
                if am:
                    questions.append(
                        {
                            "id": int(m.group(1)),
                            "stem": stem,
                            "options": options,
                            "answer": am.group(1).strip(),
                        }
                    )
                    i += 1
                    break
                om = OPTION_RE.match(line)
                if om:
                    options[om.group(1)] = om.group(2)
                i += 1
        else:
            i += 1
    return questions


def parse_multiple_choice(paras: list[str]) -> list[dict]:
    questions = []
    i = 0
    while i < len(paras):
        m = QUESTION_RE.match(paras[i])
        if m:
            stem = m.group(2)
            options = {}
            i += 1
            while i < len(paras):
                line = paras[i]
                am = ANSWER_RE.match(line)
                if am:
                    ans_str = am.group(1).strip()
                    questions.append(
                        {
                            "id": int(m.group(1)),
                            "stem": stem,
                            "options": options,
                            "answer": list(ans_str),
                        }
                    )
                    i += 1
                    break
                om = OPTION_RE.match(line)
                if om:
                    options[om.group(1)] = om.group(2)
                i += 1
        else:
            i += 1
    return questions


def parse_true_false(paras: list[str]) -> list[dict]:
    questions = []
    i = 0
    while i < len(paras):
        m = QUESTION_RE.match(paras[i])
        if m:
            stem = m.group(2)
            i += 1
            if i < len(paras):
                am = ANSWER_RE.match(paras[i])
                if am:
                    questions.append(
                        {
                            "id": int(m.group(1)),
                            "stem": stem,
                            "answer": am.group(1).strip(),
                        }
                    )
                    i += 1
        else:
            i += 1
    return questions


def detect_quiz_type(filename: str, paras: list[str]) -> str | None:
    name = filename
    if "单选" in name:
        return "单选题"
    if "多选" in name:
        return "多选题"
    if "判断" in name:
        return "判断题"

    parsed = {
        "单选题": parse_single_choice(paras),
        "多选题": parse_multiple_choice(paras),
        "判断题": parse_true_false(paras),
    }
    best_type, best_count = max(parsed.items(), key=lambda item: len(item[1]))
    return best_type if best_count > 0 else None


def normalize_quiz_text_to_paragraphs(text: str) -> list[str]:
    text = text.replace("\r\n", "\n").replace("\r", "\n")
    text = re.sub(r"(\d+)\.\s", r"\n\1. ", text)
    text = re.sub(r"([A-E])\.\s", r"\n\1. ", text)
    text = re.sub(r"答案[：:]\s*", r"\n答案：", text)

    paragraphs = []
    for line in text.split("\n"):
        line = line.strip()
        if not line:
            continue
        if re.match(r"^第\s*\d+\s*页", line):
            continue
        if re.match(r"^- \d+ -$", line):
            continue
        paragraphs.append(line)
    return paragraphs


def extract_paragraphs_from_pdf(data: bytes) -> list[str]:
    reader = PdfReader(io.BytesIO(data))
    page_texts = []
    for page in reader.pages:
        page_texts.append(page.extract_text() or "")
    return normalize_quiz_text_to_paragraphs("\n".join(page_texts))


def parse_quiz_paragraphs(paras: list[str], filename: str) -> tuple[str, list[dict]] | None:
    if not paras:
        return None

    quiz_type = detect_quiz_type(filename, paras)
    if not quiz_type:
        return None

    parsers = {
        "单选题": parse_single_choice,
        "多选题": parse_multiple_choice,
        "判断题": parse_true_false,
    }
    questions = parsers[quiz_type](paras)
    if not questions:
        return None
    return quiz_type, questions


def parse_word_file(data: bytes, filename: str) -> tuple[str, list[dict]] | None:
    paras = extract_paragraphs_from_bytes(data)
    return parse_quiz_paragraphs(paras, filename)


def parse_pdf_file(data: bytes, filename: str) -> tuple[str, list[dict]] | None:
    paras = extract_paragraphs_from_pdf(data)
    return parse_quiz_paragraphs(paras, filename)


def parse_upload_file(data: bytes, filename: str) -> tuple[str, list[dict]] | None:
    ext = Path(filename).suffix.lower()
    if ext == ".docx":
        return parse_word_file(data, filename)
    if ext == ".pdf":
        return parse_pdf_file(data, filename)
    return None


@st.cache_data(show_spinner=False)
def parse_upload_file_cached(file_hash: str, filename: str, data: bytes) -> tuple[str, list[dict]] | None:
    return parse_upload_file(data, filename)


@st.cache_data(show_spinner=False)
def load_questions(filepath: str, file_mtime_ns: int) -> tuple[str, list[dict]] | None:
    path = Path(filepath)
    content = path.read_bytes()
    file_hash = hashlib.md5(content).hexdigest()
    return parse_upload_file_cached(file_hash, path.name, content)


def sanitize_filename(filename: str) -> str:
    return Path(filename).name


def get_local_filepath(filename: str) -> Path:
    return APP_DIR / sanitize_filename(filename)


def local_file_exists(filename: str) -> bool:
    return get_local_filepath(filename).is_file()


def save_file_locally(filename: str, content: bytes) -> Path:
    filepath = get_local_filepath(filename)
    filepath.write_bytes(content)
    return filepath


def get_github_config() -> dict | None:
    try:
        return {
            "token": st.secrets["GITHUB_TOKEN"],
            "repo": st.secrets["GITHUB_REPO"],
            "branch": st.secrets.get("GITHUB_BRANCH", "main"),
        }
    except (KeyError, FileNotFoundError, AttributeError):
        return None


def github_api_headers(cfg: dict) -> dict:
    return {
        "Authorization": f"Bearer {cfg['token']}",
        "Accept": "application/vnd.github+json",
        "X-GitHub-Api-Version": "2022-11-28",
    }


def github_fetch_file(filename: str) -> tuple[bytes | None, str | None]:
    cfg = get_github_config()
    if not cfg:
        return None, None

    url = f"https://api.github.com/repos/{cfg['repo']}/contents/{filename}"
    response = requests.get(
        url,
        headers=github_api_headers(cfg),
        params={"ref": cfg["branch"]},
        timeout=30,
    )
    if response.status_code != 200:
        return None, None

    data = response.json()
    content = base64.b64decode(data["content"].replace("\n", ""))
    return content, data.get("sha")


def github_upload_file(
    filename: str,
    content: bytes,
    message: str,
    sha: str | None = None,
) -> tuple[bool, str, str | None]:
    cfg = get_github_config()
    if not cfg:
        return False, "未配置 GitHub Secrets，已跳过云端同步。", None

    safe_name = sanitize_filename(filename)
    url = f"https://api.github.com/repos/{cfg['repo']}/contents/{safe_name}"
    payload = {
        "message": message,
        "content": base64.b64encode(content).decode("ascii"),
        "branch": cfg["branch"],
    }
    if sha:
        payload["sha"] = sha

    response = requests.put(url, headers=github_api_headers(cfg), json=payload, timeout=60)
    if response.status_code in (200, 201):
        new_sha = response.json().get("content", {}).get("sha")
        return True, "", new_sha

    if response.status_code == 422 and not sha and "already exists" in response.text.lower():
        return False, "GitHub 仓库中已存在同名文件。", None

    return False, f"HTTP {response.status_code}: {response.text[:300]}", None


def upload_file_to_github(
    filename: str,
    content: bytes,
    message: str | None = None,
) -> tuple[bool, str]:
    commit_message = message or GITHUB_COMMIT_MESSAGE
    safe_name = sanitize_filename(filename)
    _, sha = github_fetch_file(safe_name)
    ok, err, _ = github_upload_file(safe_name, content, commit_message, sha=sha)
    return ok, err


def get_user_progress_local_path() -> Path:
    return APP_DIR / USER_PROGRESS_FILE


def clamp_batch_index() -> None:
    total = len(get_question_pool())
    if total == 0:
        st.session_state.batch_index = 0
        return
    max_batch = (total - 1) // st.session_state.batch_size
    st.session_state.batch_index = min(st.session_state.batch_index, max_batch)


def build_user_progress_payload() -> dict:
    return {
        "version": 1,
        "quiz_type": st.session_state.quiz_type,
        "batch_index": st.session_state.batch_index,
        "wrong_book": st.session_state.wrong_book,
    }


def apply_user_progress(data: dict) -> None:
    quiz_type = data.get("quiz_type")
    if quiz_type in QUIZ_TYPES:
        st.session_state.quiz_type = quiz_type

    wrong_book = data.get("wrong_book")
    if isinstance(wrong_book, dict):
        st.session_state.wrong_book = wrong_book

    batch_index = data.get("batch_index", 0)
    if isinstance(batch_index, int) and batch_index >= 0:
        st.session_state.batch_index = batch_index

    clamp_batch_index()


def load_user_progress() -> None:
    if st.session_state.get("user_progress_loaded"):
        return

    data = None
    try:
        remote_content, _ = github_fetch_file(USER_PROGRESS_FILE)
        if remote_content:
            try:
                data = json.loads(remote_content.decode("utf-8"))
                get_user_progress_local_path().write_bytes(remote_content)
            except (json.JSONDecodeError, UnicodeDecodeError):
                data = None
    except Exception:
        data = None

    if data is None:
        local_path = get_user_progress_local_path()
        if local_path.is_file():
            try:
                data = json.loads(local_path.read_text(encoding="utf-8"))
            except (json.JSONDecodeError, OSError):
                data = None

    if data:
        apply_user_progress(data)

    st.session_state.user_progress_loaded = True


def save_user_progress() -> None:
    try:
        payload = build_user_progress_payload()
        content = json.dumps(payload, ensure_ascii=False, indent=2).encode("utf-8")
        get_user_progress_local_path().write_bytes(content)
        upload_file_to_github(USER_PROGRESS_FILE, content, message=PROGRESS_COMMIT_MESSAGE)
    except Exception:
        pass


def register_uploaded_bank(filename: str, content: bytes, quiz_type: str, questions: list[dict]) -> str:
    file_hash = hashlib.md5(content).hexdigest()
    bank_key = f"upload_{file_hash[:10]}"
    bank_name = sanitize_filename(filename).rsplit(".", 1)[0]
    st.session_state.uploaded_banks[bank_key] = {
        "name": f"上传·{bank_name}",
        "type": quiz_type,
        "questions": questions,
        "builtin": False,
        "filename": sanitize_filename(filename),
    }
    if bank_key not in st.session_state.enabled_banks:
        st.session_state.enabled_banks.append(bank_key)
    st.session_state.processed_upload_hashes.add(file_hash)
    return f"{sanitize_filename(filename)}（{quiz_type}，{len(questions)} 题）"


def load_persisted_uploads():
    if st.session_state.get("persisted_loaded"):
        return

    for pattern in ("*.docx", "*.pdf"):
        for filepath in sorted(APP_DIR.glob(pattern)):
            if filepath.name in BUILTIN_UPLOAD_EXCLUDES:
                continue

            content = filepath.read_bytes()
            file_hash = hashlib.md5(content).hexdigest()
            if file_hash in st.session_state.processed_upload_hashes:
                continue

            result = load_questions(str(filepath), filepath.stat().st_mtime_ns)
            if not result:
                continue

            quiz_type, questions = result
            register_uploaded_bank(filepath.name, content, quiz_type, questions)

    st.session_state.persisted_loaded = True


def get_all_banks() -> dict:
    return {**BUILTIN_BANKS, **st.session_state.uploaded_banks}


def build_active_pool(quiz_type: str) -> list[dict]:
    pool = []
    for bank_key in st.session_state.enabled_banks:
        bank = get_all_banks().get(bank_key)
        if not bank or bank["type"] != quiz_type:
            continue
        for q in bank["questions"]:
            pool.append(
                {
                    **q,
                    "_uid": f"{bank_key}_{q['id']}",
                    "_bank": bank["name"],
                }
            )
    return pool

