    st.info(
        f"📊 本组成绩：答对 **{correct_count}/{batch_total}** 题 ｜ "
        f"正确率 **{accuracy:.0f}%** ｜ 得分 **{score:.0f}** 分（满分 100）"
    )

    # ── 翻页 ──
    next_start = (st.session_state.batch_index + 1) * batch_size
    has_more = next_start < total_count

    st.markdown("---")
    col1, col2 = st.columns(2)
    with col1:
        if has_more:
            if st.button(f"➡️ 进入下 {batch_size} 道题", use_container_width=True):
                st.session_state.batch_index += 1
                clear_batch_state()
                save_user_progress()
                st.rerun()
        else:
            if st.button("🎊 全部刷完，查看通关庆祝", use_container_width=True):
                st.session_state.batch_index += 1
                clear_batch_state()
                save_user_progress()
                st.rerun()
    with col2:
        if st.button("🔄 重新做本组", use_container_width=True):
            clear_batch_state()
            save_user_progress()
            st.rerun()
